bomData.valueScript:
this.length = partSelf._dimz;
this.bom_width = partSelf._dimy;
this.thickness = partSelf._dimx;

ncData.valueScript:
this.PosX = posRel.x;
this.MacroName = partSelf._id;

let drillingDiameter = partSelf._thickness / 4;
let halfPartThickness = partSelf._thickness / 2;
let drillCnt = 3;
let diff = part2._dimz / drillCnt;
for(let i=0; i<drillCnt; i++) {
  let drilling01 = partSelf.add3DElement('drilling01', this, part2._dimx + posRel.x - (2*halfPartThickness), posRel.y, posRel.z  + diff*i, halfPartThickness * 3, drillingDiameter, drillingDiameter);
  drilling01.extrude('<svg><circle cx="' + halfPartThickness + '" cy="' + halfPartThickness + '" r="' + drillingDiameter + '" /></svg>', 'x');
  }
